use alloc::{string::ToString, sync::Arc, vec, vec::Vec};
use core::ffi::c_char;
use core::iter::Iterator;

use axerrno::{AxError, AxResult};
use axfs::FS_CONTEXT;
use axhal::uspace::UserContext;
use axtask::current;
use starry_core::{mm::load_user_app, task::AsThread};
use starry_vm::vm_load_until_nul;

use crate::{file::FD_TABLE, mm::vm_load_string};

/// POSIX 规范：限制最大脚本嵌套解析层数
const MAX_SHEBANG_DEPTH: usize = 4;
/// Linux 规范：Shebang 行的最大安全读取字节数
const MAX_SHEBANG_LINE: usize = 128;

pub fn sys_execve(
    uctx: &mut UserContext,
    path: *const c_char,
    argv: *const *const c_char,
    envp: *const *const c_char,
) -> AxResult<isize> {
    let raw_path = vm_load_string(path)?;

    // =====================================================================
    // 率先完成路径的绝对化转化，杜绝相对路径引发的 VFS 找不到文件
    // =====================================================================
    let mut current_path = match FS_CONTEXT.lock().resolve(&raw_path) {
        Ok(loc) => loc.absolute_path()?.to_string(),
        Err(_) => return Err(AxError::NotFound), // 连路径都无法解析，直接NotFound
    };

    let mut args = if argv.is_null() {
        Vec::new()
    } else {
        vm_load_until_nul(argv)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };

    let envs = if envp.is_null() {
        Vec::new()
    } else {
        vm_load_until_nul(envp)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };

    debug!("sys_execve <= absolute_path: {current_path:?}, args: {args:?}, envs: {envs:?}");

    // --- POSIX 标准 Shebang (#!) 递归解析器 ---
    let mut depth = 0;
    let mut is_script_without_shebang = false;

    loop {
        if depth >= MAX_SHEBANG_DEPTH {
            error!("sys_execve: Shebang substitution depth exceeded maximum limit");
            return Err(AxError::InvalidInput);
        }

        // 此时 current_path 已经是绝对路径（如 /glibc/test.sh），File::open 百分之百能正确打开！
        let file = {
            let fs_ctx = FS_CONTEXT.lock();
            match axfs::File::open(&*fs_ctx, current_path.as_str()) {
                Ok(f) => f,
                Err(_) => {
                    // 如果文件不存在，直接返回未找到，不应该往后走
                    return Err(AxError::NotFound);
                }
            }
        };

        let mut raw_buf = [0u8; MAX_SHEBANG_LINE];
        let mut slice: &mut [u8] = &mut raw_buf[..];
        let bytes_read = file.read(&mut slice).unwrap_or(0);

        if bytes_read >= 4 && &raw_buf[0..4] == b"\x7fELF" {
            is_script_without_shebang = false;
            break; 
        }

        if bytes_read < 2 || &raw_buf[0..2] != b"#!" {
            is_script_without_shebang = true;
            break; 
        }

        // 以下是原汁原味的 Shebang 提取解析逻辑
        let first_line = match raw_buf[2..bytes_read].split(|&b| b == b'\n').next() {
            Some(line) => line,
            None => break,
        };

        let line_str = match core::str::from_utf8(first_line) {
            Ok(s) => s.trim(),
            Err(_) => return Err(AxError::InvalidInput),
        };

        if line_str.is_empty() {
            return Err(AxError::InvalidInput);
        }

        let mut parts = line_str.split_whitespace();
        let interpreter = match parts.next() {
            Some(p) => p.to_string(),
            None => return Err(AxError::InvalidInput),
        };
        let interp_arg = parts.next().map(|s| s.to_string());

        let mut new_args = vec![interpreter.clone()];
        if let Some(arg) = interp_arg {
            new_args.push(arg);
        }
        new_args.push(current_path.clone());
        if !args.is_empty() {
            new_args.extend(args.into_iter().skip(1));
        }

        current_path = interpreter;
        args = new_args;
        depth += 1;
    }

    // =====================================================================
    // 纯文本脚本保底机制
    // =====================================================================
    if is_script_without_shebang {
        debug!("sys_execve: No-shebang script detected. Triggering /bin/sh fallback.");

        // 传入给 /bin/sh 的必须是前面已经固化好的绝对路径 current_path
        let mut fallback_args = vec!["/bin/sh".to_string(), current_path.clone()];
        if args.len() > 1 {
            // 保留原脚本后面携带的参数（如 date.lua）
            fallback_args.extend(args.into_iter().skip(1));
        }

        current_path = "/bin/sh".to_string();
        args = fallback_args;
    }

    let curr = current();
    let proc_data = &curr.as_thread().proc_data;

    if proc_data.proc.threads().len() > 1 {
        error!("sys_execve: multi-thread not supported");
        return Err(AxError::WouldBlock);
    }

    let mut aspace = proc_data.aspace.lock();
    let (entry_point, user_stack_base) =
        load_user_app(&mut aspace, Some(current_path.as_str()), &args, &envs)?;
    drop(aspace);

    error!(
        "execve loaded {}: entry={:#x} sp={:#x}",
        current_path,
        entry_point.as_usize(),
        user_stack_base.as_usize()
    );

    // exec 会重建用户地址空间，必须同步重置 brk 游标，避免沿用旧镜像的 heap_top。
    proc_data.set_heap_bottom(starry_core::config::USER_HEAP_BASE);
    proc_data.set_heap_top(starry_core::config::USER_HEAP_BASE);

    let loc = FS_CONTEXT.lock().resolve(&current_path)?;
    curr.set_name(loc.name());

    *proc_data.exe_path.write() = loc.absolute_path()?.to_string();
    *proc_data.cmdline.write() = Arc::new(args);

    *proc_data.signal.actions.lock() = Default::default();

    let mut fd_table = FD_TABLE.write();
    let cloexec_fds = fd_table
        .ids()
        .filter(|it| fd_table.get(*it).unwrap().cloexec)
        .collect::<Vec<_>>();
    for fd in cloexec_fds {
        fd_table.remove(fd);
    }
    drop(fd_table);

    uctx.set_ip(entry_point.as_usize());
    uctx.set_sp(user_stack_base.as_usize());
    Ok(0)
}

