fn flush_file_system() {
    // 先刷全部脏页缓存，确保页面缓存中的数据落盘后再卸载文件系统
    let _ = axfs::sync_filesystems();
    let cx = FS_CONTEXT.lock();
    let _ = cx.root_dir().unmount_all();
    let _ = cx.root_dir().filesystem().flush();
}

