use alloc::string::String;
use alloc::vec;
use axfs::FS_CONTEXT;
use axlog::ax_println;

/// 内核态白盒文件写入辅助函数
fn kernel_write_file(path: &str, content: &str) {
    let cx = FS_CONTEXT.lock();
    let res = axfs::OpenOptions::new()
        .write(true)
        .create(true)
        .open(&*cx, path)
        .unwrap_or_else(|e| panic!("内核高级接口打开 {} 失败: {:?}", path, e));

    let file = match res {
        axfs::OpenResult::File(f) => f,
        _ => panic!("目标路径 {} 不是文件", path),
    };

    let mut buf = content.as_bytes(); 
    file.write_at(&mut buf, 0)
        .unwrap_or_else(|e| panic!("内核高级数据写入 {} 失败: {:?}", path, e));
}

/// 内核态自动化评测总路由 (MoonOS 版本)
pub fn run_all_contest_tests() {
    ax_println!("\x1b[94m[CONTEST] MoonOS 自动化评测机制启动，正在加载总控脚本...\x1b[0m");

    // 1. 静态加载打包进内核的全新总控脚本与 LTP 模板
    let ltp_template = include_str!("../scripts/ltp_template.sh");

    #[cfg(target_arch = "riscv64")]
    let moon_master_script = include_str!("../scripts/moon_master_test-rv.sh");

    #[cfg(target_arch = "loongarch64")]
    let moon_master_script = include_str!("../scripts/moon_master_test-la.sh");

    let cases = include_str!("../scripts/cases.txt");

    // 2. 将控制权释放写回虚拟文件系统的根目录
    kernel_write_file("cases.txt", cases);
    kernel_write_file("ltp_run.sh", ltp_template);
    kernel_write_file("moon_master_test.sh", moon_master_script);

    ax_println!("\x1b[92m[CONTEST] moon_master_test.sh 自适应固化与释放成功！\x1b[0m");

    // 3. 构建拉起参数，直接使用外部已经完整封装好的自动化测试链
    let args = vec![
        String::from("/musl/busybox"),
        String::from("sh"),
        String::from("/moon_master_test.sh"),
    ];
    let envs: vec::Vec<String> = vec![];

    // 4. 将系统移交给用户态脚本总控
    let exit_code = crate::entry::run_initproc(&args, &envs);
    ax_println!("\x1b[32m[CONTEST] MoonOS 评测总控退出，状态码: {}\x1b[0m", exit_code);
}

